const token = process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
const locationId = process.env.GHL_LOCATION_ID || 'TW8JsPW5NMnA3tfK2XLn';
const base = 'https://services.leadconnectorhq.com';
const headers = { Authorization: `Bearer ${token}`, Version: '2021-07-28', 'Content-Type': 'application/json' };

const now = Date.now();
const windowMs = 30 * 60 * 1000;
const since = now - windowMs;

const res = await fetch(`${base}/conversations/search?locationId=${locationId}&limit=100`, { headers });
if (!res.ok) throw new Error(`conversation search failed: ${res.status} ${await res.text()}`);
const data = await res.json();
const conversations = data.conversations || [];

const candidates = conversations.filter(c => (c.lastMessageDate || 0) >= since && String(c.lastMessageDirection||'').toLowerCase() === 'inbound');

const routineKeywords = /(password|forgot password|reset|login|log in|access|can'?t access|billing|charge|invoice|receipt|payment)/i;
const complexKeywords = /(refund|money back|chargeback|dispute|fraud|lawyer|legal|bbb|angry|frustrated|disappointed|complaint|cancel.*subscription|cancellation)/i;

const out = { nowIso: new Date(now).toISOString(), sinceIso: new Date(since).toISOString(), totalConversations: conversations.length, candidates: [] };

for (const c of candidates) {
  const mRes = await fetch(`${base}/conversations/${c.id}/messages?limit=20`, { headers });
  const mJson = await mRes.json();
  const msgs = mJson?.messages?.messages || [];
  const inbound = msgs.find(m => String(m.direction).toLowerCase() === 'inbound') || msgs[0];
  const body = inbound?.body || c.lastMessageBody || '';
  const isComplex = complexKeywords.test(body);
  const isRoutine = routineKeywords.test(body) && !isComplex;
  let category = 'other';
  if (isComplex) category = 'complex';
  else if (isRoutine) category = 'routine';

  let confidence = 0.55;
  if (category === 'complex') confidence = 0.95;
  if (category === 'routine') confidence = 0.92;

  out.candidates.push({
    conversationId: c.id,
    contactId: c.contactId,
    contactName: c.contactName || c.fullName,
    channelType: c.lastMessageType,
    unreadCount: c.unreadCount,
    lastMessageDate: new Date(c.lastMessageDate).toISOString(),
    snippet: String(body).slice(0,180),
    category,
    confidence,
    messagesChecked: msgs.length
  });
}

console.log(JSON.stringify(out, null, 2));

const BASE='https://services.leadconnectorhq.com';
const LOCATION=process.env.GHL_LOCATION_ID||'TW8JsPW5NMnA3tfK2XLn';
const TOKEN=process.env.GHL_PRIVATE_INTEGRATION_TOKEN;
if(!TOKEN){ console.log(JSON.stringify({ok:false,error:'Missing GHL token'})); process.exit(0); }

const headers={Authorization:`Bearer ${TOKEN}`,Version:'2021-07-28','Content-Type':'application/json',Accept:'application/json'};
const sleep=(ms)=>new Promise(r=>setTimeout(r,ms));
async function req(method,path,body){
  const r=await fetch(BASE+path,{method,headers,body:body?JSON.stringify(body):undefined});
  const t=await r.text();
  let j={}; try{j=t?JSON.parse(t):{}}catch{j={raw:t}};
  if(!r.ok) throw new Error(`${method} ${path} -> ${r.status} ${t.slice(0,240)}`);
  await sleep(350);
  return j;
}
const toMs=(v)=>{ const n=Number(v); if(Number.isFinite(n)&&n>0) return n<1e12?n*1000:n; const d=Date.parse(v); return Number.isFinite(d)?d:0; };

function classify(text){
  const t=(text||'').toLowerCase();
  const complexKW=['refund','money back','chargeback','dispute','angry','frustrated','disappointed','complaint','cancel and refund','lawyer','legal','bbb','fraud'];
  const passwordKW=['password','forgot password','reset'];
  const accessKW=['access','login','log in','course access','can\'t get in','cannot get in'];
  const billingKW=['billing','invoice','receipt','payment','charged','charge','subscription'];
  if(complexKW.some(k=>t.includes(k))) return {category:'complex',reason:'refund/complaint sentiment',confidence:0.97};
  if(passwordKW.some(k=>t.includes(k))) return {category:'routine',sub:'password',confidence:0.96};
  if(accessKW.some(k=>t.includes(k))) return {category:'routine',sub:'access',confidence:0.92};
  if(billingKW.some(k=>t.includes(k))) return {category:'routine',sub:'billing',confidence:0.9};
  return {category:'complex',reason:'unrecognized or nuanced',confidence:0.6};
}

function routineTemplate(sub, name='there'){
  if(sub==='password') return `Hi ${name},\n\nHere's how to reset your password:\n1. Go to members.truthjblue.com/forgot-password\n2. Click \"Forgot Password\"\n3. Check your email for reset link\n\nIf you don't see it, check spam. Let me know if you need more help!`;
  if(sub==='access') return `Hi ${name},\n\nYour course access is ready:\n1. Log in at members.truthjblue.com\n2. Use the email on your purchase\n3. Look for your course in your dashboard\n\nFirst lesson tip: Start with Module 1, then complete the action step before moving on.`;
  return `Hi ${name},\n\nI can help with your billing question. I can confirm your purchase details and resend a receipt if needed.\n\nReply with the best email for your account and I’ll verify it right away.`;
}

function complexDraft(name='there'){
  return `Hi ${name},\n\nThank you for reaching out — I’m sorry this has been frustrating. I’ve flagged your message for priority review so we can get this resolved properly.\n\nA support specialist will follow up as quickly as possible.`;
}

const now=Date.now();
const cutoff=now-(30*60*1000);

const summary={
  ok:true,
  scannedConversations:0,
  messagesProcessed:0,
  autoResponsesSent:0,
  routineDrafts:0,
  escalationsFlagged:0,
  escalationItems:[],
  errors:[]
};

try{
  let conv=[];
  for(const p of [`/conversations/search?locationId=${LOCATION}&limit=100`,`/conversations/search?location_id=${LOCATION}&limit=100`]){
    try{ const r=await req('GET',p); if(Array.isArray(r.conversations)){ conv=r.conversations; break; } }catch{}
  }
  summary.scannedConversations=conv.length;

  for(const c of conv){
    const convId=c.id;
    const contactId=c.contactId||c.contact_id;
    const unread=Number(c.unreadCount||c.unread_count||0);
    const lastMs=toMs(c.lastMessageDate||c.last_message_date||c.dateUpdated||c.date_updated||c.dateAdded||c.date_added);
    const direction=String(c.lastMessageDirection||c.last_message_direction||'').toLowerCase();
    if(!contactId||!convId) continue;
    if(!(unread>0 && direction==='inbound' && lastMs>=cutoff)) continue;

    let contactName='there', contactEmail='', contactPhone='';
    try{
      const ct=await req('GET',`/contacts/${contactId}`);
      const cd=ct.contact||ct;
      contactName=cd.firstName||cd.contactName||'there';
      contactEmail=cd.email||'';
      contactPhone=cd.phone||'';
    }catch(e){ summary.errors.push(`contact ${contactId}: ${e.message}`); }

    let latestInbound='';
    try{
      const m=await req('GET',`/conversations/${convId}/messages?limit=20`);
      const rows=m.messages||[];
      for(const msg of rows){
        const dir=String(msg.direction||msg.messageDirection||'').toLowerCase();
        const ms=toMs(msg.dateAdded||msg.date_added||msg.timestamp);
        if(dir==='inbound' && ms>=cutoff){ latestInbound=(msg.body||msg.message||msg.text||'').trim(); break; }
      }
      if(!latestInbound){
        const fallback=rows.find(x=>String(x.direction||x.messageDirection||'').toLowerCase()==='inbound');
        if(fallback) latestInbound=(fallback.body||fallback.message||fallback.text||'').trim();
      }
    }catch(e){ summary.errors.push(`messages ${convId}: ${e.message}`); }

    const cls=classify(latestInbound);
    summary.messagesProcessed++;

    if(cls.category==='routine'){
      const draft=routineTemplate(cls.sub, contactName);
      summary.routineDrafts++;
      if(cls.confidence>=0.9){
        try{
          await req('POST','/conversations/messages',{
            type: contactPhone ? 'SMS' : 'Email',
            contactId,
            message: draft,
            ...(contactEmail && !contactPhone ? {subject:'Support Update'} : {})
          });
          summary.autoResponsesSent++;
        }catch(e){ summary.errors.push(`send ${contactId}: ${e.message}`); }
      }
    } else {
      summary.escalationsFlagged++;
      const draft=complexDraft(contactName);
      summary.escalationItems.push({contactId,convId,preview:(latestInbound||'').slice(0,140),reason:cls.reason||'complex'});
      try{
        const ct=await req('GET',`/contacts/${contactId}`);
        const cd=ct.contact||ct;
        const prev=cd.notes||'';
        const stamp=new Date().toISOString();
        const note=`[${stamp}] Escalation draft saved: ${draft}`;
        await req('PUT',`/contacts/${contactId}`,{notes: (prev?`${prev}\n\n`:'')+note});
      }catch(e){ summary.errors.push(`note ${contactId}: ${e.message}`); }
    }
  }

}catch(e){ summary.ok=false; summary.errors.push(e.message); }

console.log(JSON.stringify(summary,null,2));
